import { MultiMap } from '../src/multimap'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("add and get", (() => { const m = new MultiMap<string,number>(); m.add("a",1).add("a",2); return m.get("a") })(), [1,2])
await check("get missing", new MultiMap().get("x"), [])
await check("has true", (() => { const m = new MultiMap<string,number>(); m.add("a",1); return m.has("a") })(), true)
await check("has false", new MultiMap().has("x"), false)
await check("totalSize", (() => { const m = new MultiMap<string,number>(); m.add("a",1).add("a",2).add("b",3); return m.totalSize() })(), 3)
await check("deleteEntry", (() => { const m = new MultiMap<string,number>(); m.add("a",1).add("a",2); m.deleteEntry("a",1); return m.get("a") })(), [2])
await check("delete all removes key", (() => { const m = new MultiMap<string,number>(); m.add("a",1); m.delete("a"); return m.has("a") })(), false)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
